import requests
import json

GMAIL_GET_URL = "http://localhost:39919/gmail/messages/get"

message_ids = ["msg_1601", "msg_1602", "msg_1603", "msg_1604", "msg_1605", "msg_1606", "msg_1607"]

def get_message(msg_id):
    try:
        resp = requests.post(GMAIL_GET_URL, json={"message_id": msg_id}, timeout=30)
        return {"msg_id": msg_id, "data": resp.json() if resp.status_code == 200 else {"error": resp.text}, "status": resp.status_code}
    except Exception as e:
        return {"msg_id": msg_id, "error": str(e)}

# 并行读取所有邮件
from concurrent.futures import ThreadPoolExecutor, as_completed
messages = {}
with ThreadPoolExecutor(max_workers=7) as executor:
    futures = {executor.submit(get_message, mid): mid for mid in message_ids}
    for future in as_completed(futures):
        result = future.result()
        messages[result["msg_id"]] = result

# 打印并按客户整理
print("=== 邮件详情 ===")
for mid in message_ids:
    msg = messages[mid]
    print(f"\n[{mid}] Status: {msg.get('status', 'unknown')}")
    if "data" in msg:
        data = msg["data"]
        print(f"From: {data.get('from', 'N/A')}")
        print(f"Subject: {data.get('subject', 'N/A')}")
        body = data.get('body', 'N/A')
        print(f"Body Preview: {body[:300] if body else 'N/A'}...")
    elif "error" in msg:
        print(f"Error: {msg['error']}")
